+    #[test]
+    fn pane_fingerprint_hash_in_hashset() {
+        use std::collections::HashSet;
+        let fp1 = PaneFingerprint {
+            domain: "a".into(),
+            initial_title: "b".into(),
+            initial_cwd: "c".into(),
+            content_hash: 0,
+        };
+        let fp2 = fp1.clone();
+        let fp3 = PaneFingerprint {
+            domain: "x".into(),
+            ..fp1.clone()
+        };
+        let mut set = HashSet::new();
+        set.insert(fp1);
+        set.insert(fp2); // duplicate
+        set.insert(fp3);
+        assert_eq!(set.len(), 2);
+    }
